export const MainBanner = () => {
  const { slug } = useParams();
  const invitedFriendInfo = INVITED_FRIENDS_INFO[slug as keyof typeof INVITED_FRIENDS_INFO];
  const [parallaxOffset, setParallaxOffset] = useState(0);

  useEffect(() => {
    let frameId: number | null = null;
    const PARALLAX_SPEED = 0.12;

    const handleScroll = () => {
      if (frameId !== null) {
        return;
      }

      frameId = window.requestAnimationFrame(() => {
        setParallaxOffset(window.scrollY * PARALLAX_SPEED);
        frameId = null;
      });
    };

    handleScroll();
    window.addEventListener("scroll", handleScroll, { passive: true });

    return () => {
      if (frameId !== null) {
        window.cancelAnimationFrame(frameId);
      }
      window.removeEventListener("scroll", handleScroll);
    };
  }, []);

  return (
    <>
      <section
        className={`${styles.section}`}
        style={{ "--parallax-offset": `${parallaxOffset}px` } as CSSProperties}
      >
        <div className={`${styles.heroContent} ${styles.container}`}>
          <div className={styles.logoWrapper}>
            <WeddingSvg />
            <NamesSvg />
          </div>
          <p className={styles.subtitle}>{invitedFriendInfo?.welcome}, приглашаем <br/> тебя на нашу свадьбу!</p>
          <div className={styles.dateWrapper}>
            <p className={styles.date}>22 Мая 2026</p>
            <p className={styles.country}>Грузия</p>
          </div>
        </div>


    </section>
    <div className={styles.topNav}>
      <div className={`${styles.container} ${styles.navRow}`}>
        <Image src={Headerlogo} alt='header-logo' />
        <span className={styles.dateHeader}>
          <span>22 мая</span>
          <span className={styles.year}>2026</span>
        </span>
        <div className={styles.linksWrapper}>
          <span>Приглашение</span>
          <span>Место проведения</span>
          <span>Как добраться</span>
          <span>Где жить</span>
          <span>Дресс-код</span>
          <span>Расписание</span>
          <span>Что дарить</span>
        </div>
      </div>
  </div>
  </>

  );
}

